$$
\text{Lợi nhận} = \text{Doanh thu} - \text{Chi phí} \quad P(x) = R(x) - f(x) = x^2 + 2x - \frac{2}{7}(x+4) - \frac{d}{2x+1}
$$

$$
\text{Vậy } f(x) = \frac{2}{7}(x+4) + \frac{145}{28} \cdot \frac{1}{2x+1} \text{ có đạo hàm } f'(x) = \frac{2}{7} - \frac{290}{28(2x+1)^2} = 0 \Leftrightarrow \begin{cases} x = \frac{\sqrt{145}-2}{4} \text{ (nhan)} \\ x = \frac{-\sqrt{145}-2}{4} \text{ (loai)} \end{cases}
$$
